using System.Net;using System.Net.Http.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Bad case: Try to create audit log with missing required fields/// Expected: 400 Bad Request/// </summary>public class AuditServiceTests_CreateAuditLog_WithInvalidData_ShouldReturnBadRequest : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "AuditService"    };    [SkippableFact]    public async Task CreateAuditLog_WithMissingAction_ShouldReturnBadRequest()    {        await AuthenticateAsAdminAsync(AuditClient);        var request = new         {             actorId = TestSeedData.DoctorUserId,             targetId = TestSeedData.PatientUserId,             targetType = "EHR",             description = "Test audit"         };        var response = await PostAsJsonWithRetryAsync(AuditClient, ApiEndpoints.Audit.Create, request);        Assert.True(            response.StatusCode == HttpStatusCode.BadRequest ||             response.StatusCode == HttpStatusCode.UnprocessableEntity,            $"Expected 400 or 422, got {response.StatusCode}");    }}
